import hashlib
import json
from pathlib import Path

class EmbeddingCache:
    """File-based embedding cache with SHA-256 keys."""

    def __init__(self, cache_dir: str = ".embedding_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)

    def _key(self, model: str, text: str) -> str:
        """Generate SHA-256 key."""
        combined = f"{model}:{text}".encode()
        return hashlib.sha256(combined).hexdigest()

    def get(self, model: str, text: str) -> list[float] | None:
        """Retrieve embedding from cache."""
        key = self._key(model, text)
        path = self.cache_dir / f"{key}.json"
        if path.exists():
            with open(path) as f:
                return json.load(f)
        return None

    def put(self, model: str, text: str, embedding: list[float]) -> None:
        """Store embedding in cache."""
        key = self._key(model, text)
        path = self.cache_dir / f"{key}.json"
        with open(path, "w") as f:
            json.dump(embedding, f)

import torch from sentence_transformers import SentenceTransformer import numpy as np
device = "cuda" if torch.cuda.is_available() else "cpu" # Instantiate ONCE per process — multiple instances OOM on GPU model = SentenceTransformer("BAAI/bge-large-en-v1.5", device=device)
def get_local_embeddings_batch( texts: list[str], batch_size: int = 32 ) -> np.ndarray: """Batch embedding with local model.""" return model.encode( texts, batch_size=batch_size, show_progress_bar=True, convert_to_numpy=True, normalize_embeddings=True, )
